import { d3_tree, d3_hierarchy } from "../../../core/d3-constants";
import { Registry } from "../../../core/zc-registry";
import { isArray, getParserVal } from "../../../utils/zcutils";
import { NULL } from "../../../core/zc-constants";

export function getTreeLayout(spec, seriesdata){

    
    let { config, data } = spec;

    if(!data){
        data = seriesdata || this.data; //3d array data
    }

    let columnInfo = this.getColumnByColumnName(spec.column),
        { dataindex } =  columnInfo;

    

    //use d3.hierarchy to compute children
    let root = d3_hierarchy(data, function(d) {
        return getChildren(d);
    }).sum(function(d) {
        return getValue(d, dataindex);
    });


    root.descendants();

     
    // Compute the layout.

    let dimension = getParserVal(config.size, null, config.size, this);

    const padding = 1,
          dx = 10,
          dy = dimension[0] / (root.height + padding);
    
          
    let tree = d3_tree().size(dimension).nodeSize([dx, dy])
                    .separation(function(a,b){
                        return a.parent == b.parent ? 1 : 2;
                    });

    let layout = tree(root);

    // Center the tree.
    let x0 = Infinity;
    let x1 = -x0;
    root.each(d => {
        if (d.x > x1) x1 = d.x;
        if (d.x < x0) x0 = d.x;
    });

    

    // Compute the default height.
    layout.x0 = x0;
    layout.x1 = x1;
    layout.viewHeight = x1 - x0 + dx * 2;

    return layout;
}
function getLevel(node){
    return node.level || (node.data && node.data.level);
}
function getValue(d, dataindex) {
    var y = d[dataindex];

    // if (treemapUtils.isDisabled(curSeriesData, d)) {
    //     return 0;
    // }

    if (y < 0) {
        return 0;
    }
    return y;
};

function getChildren(node) {
    var level = getLevel(node),
        depth = level && level.split('_').length;

        // !this.chartObj.dataObject.hasHierarchyData
    if (0 && depth == 1 && node.length < 2 && node[0] && isArray(node[0][0])) {
        return node[0];
    } else if (isArray(node[0])) {
        return node;
    } else {
        return NULL;
    }
};

Registry.setComponent("tree_layout", getTreeLayout);